def _is_safe_string(value: str) -> bool:
    return bool(_SAFE_STRING_RE.match(value))


def _validate_json_body(req: func.HttpRequest, required_fields: list[str]) -> tuple[dict | None, str | None]:
    """Parse JSON body and verify required fields exist and are strings."""
    try:
        body = req.get_json()
    except (ValueError, TypeError):
        return None, "Invalid or missing JSON body."
    if not isinstance(body, dict):
        return None, "JSON body must be an object."
    for field in required_fields:
        if field not in body:
            return None, f"Missing required field: '{field}'."
        if not isinstance(body[field], str):
            return None, f"Field '{field}' must be a string."
        if not _is_safe_string(body[field]):
            return None, f"Field '{field}' contains disallowed characters."
    return body, None


