def _check_api_key(req: func.HttpRequest) -> bool:
    """Validate Bearer token against the configured API_KEY."""
    if not API_KEY:
        # No key configured – skip check (development convenience).
        return True
    auth = req.headers.get("Authorization", "")
    if auth.startswith("Bearer "):
        token = auth[7:]
        return secrets.compare_digest(token, API_KEY)
    return False


def _generate_csrf_token() -> str:
    return secrets.token_hex(32)


def _validate_csrf(req: func.HttpRequest) -> bool:
    """Double-submit cookie pattern: cookie value must match header value."""
    cookie_header = req.headers.get("Cookie", "")
    cookie_token = None
    for part in cookie_header.split(";"):
        part = part.strip()
        if part.startswith(f"{CSRF_TOKEN_COOKIE}="):
            cookie_token = part.split("=", 1)[1]
            break
    header_token = req.headers.get(CSRF_TOKEN_HEADER)
    if not cookie_token or not header_token:
        return False
    return secrets.compare_digest(cookie_token, header_token)


